public static boolean areEqual(Object o1, Object o2) {
    if (o1 == o2) {
        return true;
    }
    if (o1 == null || o2 == null) {
        return false;
    }
    if (isArray(o1)) {
        return isArray(o2) && areArraysEqual(o1, o2);
    }
    return safeEquals(o1, o2);
}

private static boolean safeEquals(Object o1, Object o2) {
    if (o1.getClass() != o2.getClass()) {
        return false;
    }
    return o1.equals(o2);
}
